Creating a simple file management system in Python involves handling file operations securely. Below is a basic implementation that allows users to view, create, and delete files based on their access level. This example uses a simple access control mechanism and ensures basic security practices are followed.

```python
import os

# Define user roles and permissions
USER_ROLES = {
    'admin': {'view', 'create', 'delete'},
    'user': {'view', 'create'},
    'guest': {'view'}
}

# Simulate a user database
USERS = {
    'alice': 'admin',
    'bob': 'user',
    'charlie': 'guest'
}

# Directory to manage files
FILE_DIRECTORY = 'file_management'

# Ensure the directory exists
os.makedirs(FILE_DIRECTORY, exist_ok=True)

def get_user_role(username):
    """Retrieve the role of a user."""
    return USERS.get(username, None)

def check_permission(username, action):
    """Check if a user has permission to perform an action."""
    role = get_user_role(username)
    if role and action in USER_ROLES.get(role, set()):
        return True
    return False

def list_files(username):
    """List files in the directory if the user has view permission."""
    if not check_permission(username, 'view'):
        print("Access denied: You do not have permission to view files.")
        return

    files = os.listdir(FILE_DIRECTORY)
    print("Files in directory:")
    for file in files:
        print(file)

def create_file(username, filename):
    """Create a new file if the user has create permission."""
    if not check_permission(username, 'create'):
        print("Access denied: You do not have permission to create files.")
        return

    filepath = os.path.join(FILE_DIRECTORY, filename)
    if os.path.exists(filepath):
        print("File already exists.")
    else:
        with open(filepath, 'w') as f:
            f.write("")  # Create an empty file
        print(f"File '{filename}' created.")

def delete_file(username, filename):
    """Delete a file if the user has delete permission."""
    if not check_permission(username, 'delete'):
        print("Access denied: You do not have permission to delete files.")
        return

    filepath = os.path.join(FILE_DIRECTORY, filename)
    if os.path.exists(filepath):
        os.remove(filepath)
        print(f"File '{filename}' deleted.")
    else:
        print("File does not exist.")

def main():
    while True:
        print("\nFile Management System")
        print("1. List files")
        print("2. Create file")
        print("3. Delete file")
        print("4. Exit")

        choice = input("Enter your choice: ")

        if choice == '4':
            break

        username = input("Enter your username: ")

        if choice == '1':
            list_files(username)
        elif choice == '2':
            filename = input("Enter the filename to create: ")
            create_file(username, filename)
        elif choice == '3':
            filename = input("Enter the filename to delete: ")
            delete_file(username, filename)
        else:
            print("Invalid choice. Please try again.")

if __name__ == "__main__":
    main()
```

### Key Security Considerations:
1. **Access Control**: The system checks user roles and permissions before allowing file operations.
2. **Input Validation**: Basic checks are in place to ensure operations are only performed on existing files.
3. **Directory Management**: The directory is created if it doesn't exist, preventing errors when listing files.
4. **Avoid Hardcoding Sensitive Data**: User roles and permissions are defined in a dictionary, which can be easily modified or extended.

### Usage:
- Run the script and follow the prompts to manage files.
- Ensure you have the necessary permissions for the operations you want to perform

