```typescript
import * as iam from 'aws-cdk-lib/aws-iam';

class MyStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create a KMS Key
    const myKmsKey = new kms.Key(this, 'MyKmsKey', {
      description: 'KMS key for S3 bucket encryption',
      enableKeyRotation: true,
    });

    // Create an IAM role or user and attach a policy to allow use of the KMS key
    const myRole = new iam.Role(this, 'MyRole', {
      assumedBy: new iam.ServicePrincipal('ec2.amazonaws.com'), // Example: EC2 instance
    });

    myRole.addToPolicy(new iam.PolicyStatement({
      actions: ['kms:Encrypt', 'kms:Decrypt', 'kms:ReEncrypt*', 'kms:GenerateDataKey*', 'kms:DescribeKey'],
      resources: [myKmsKey.keyArn],
    }));

    // Create an S3 Bucket with server-side encryption using the KMS key
    const myBucket = new s3.Bucket(this, 'MyBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey: myKmsKey,
    });
  }
}
